def rotateDuplicates(nums):
    return False

class Solution:
    def rotateDuplicates(self, nums: list[int]) -> bool:
        sorted_nums = self.sortArray(nums)
        for i in range(len(sorted_nums) - 2):
            if sorted_nums[i] == sorted_nums[i + 2] and sorted_nums[i] == sorted_nums[i + 1]:
                return True
        return False

    def sortArray(self, nums: list[int]) -> list[int]:
        quicksort(nums, 0, len(nums) - 1)
        return nums

    def quicksort(self, nums: list[int], start: int, end: int) -> None:
        if start < end:
            pivot = self.partition(nums, start, end)
            self.quicksort(nums, start, pivot - 1)
            self.quicksort(nums, pivot + 1, end)

    def partition(self, nums: list[int], start: int, end: int) -> int:
        pivot = nums[end]
        i = start - 1
        for j in range(start, end):
            if nums[j] < pivot:
                i += 1
                nums[i], nums[j] = nums[j], nums[i]
        nums[i + 1], nums[end] = nums[end], nums[i + 1]
        return i + 1

