#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    bool rotateDuplicates(vector<int>& nums) {
        sort(nums.begin(), nums.end());
        int count = 0;
        for (int i = 0; i < nums.size() - 2; i++) {
            if (nums[i] == nums[i + 2] && nums[i] == nums[i + 1]) {
                return true;
            }
        }
        return false;
    }
};

int main() {
    Solution solution;
    vector<int> nums = {1, 3, 2, 4, 5, 1};
    bool result = solution.rotateDuplicates(nums);
    cout << boolalpha << result << endl;
